using UnityEngine;
using UnityEngine.Rendering.Universal; // Se der erro, troca para: UnityEngine.Experimental.Rendering.Universal

public class DayNightCycle2D : MonoBehaviour
{
    [Header("Reference")]
    [SerializeField] private Light2D globalLight;

    [Header("Cycle")]
    [Tooltip("Seconds for a full cycle: Day -> Dusk -> Night -> Day")]
    [SerializeField] private float cycleLength = 180f;

    [SerializeField] private bool autoRun = true;

    [Range(0f, 1f)]
    public float time01 = 0f; // 0..1 (debug / manual control)

    [Header("Hora do Dia (para WorldState / condições de NPC)")]
    [Tooltip("A partir daqui (0-1) considera-se 'Tarde'.")]
    [Range(0f, 1f)] public float afternoonStart = 0.25f;
    [Tooltip("A partir daqui (0-1) considera-se 'Noite'.")]
    [Range(0f, 1f)] public float nightStart = 0.5f;
    [Tooltip("A partir daqui (0-1) considera-se 'Madrugada'.")]
    [Range(0f, 1f)] public float dawnStart = 0.75f;

    [Header("Presets")]
    public Color dayColor = new Color(1f, 0.98f, 0.92f);
    public float dayIntensity = 1.1f;

    public Color duskColor = new Color(1f, 0.62f, 0.35f);
    public float duskIntensity = 0.75f;

    public Color nightColor = new Color(0.25f, 0.35f, 0.60f);
    public float nightIntensity = 0.35f;

    private void Reset()
    {
        globalLight = FindObjectOfType<Light2D>();
    }

    private void Update()
    {
        if (autoRun)
        {
            time01 += Time.deltaTime / Mathf.Max(0.01f, cycleLength);
            if (time01 > 1f) time01 -= 1f;
        }

        WorldState.Instance?.SetTimeOfDay(GetTimeOfDay());

        if (globalLight == null) return;

        ApplyLighting(time01);
    }

    /// <summary>Converte time01 num TimeOfDay para o WorldState (condições de NPC).</summary>
    public TimeOfDay GetTimeOfDay()
    {
        if (time01 < afternoonStart) return TimeOfDay.Manha;
        if (time01 < nightStart) return TimeOfDay.Tarde;
        if (time01 < dawnStart) return TimeOfDay.Noite;
        return TimeOfDay.Madrugada;
    }

    public void ApplyLighting(float t)
    {
        // 0.00 -> 0.45 : Day to Dusk
        // 0.45 -> 0.65 : Dusk to Night
        // 0.65 -> 1.00 : Night to Day
        if (t < 0.45f)
        {
            float u = Mathf.InverseLerp(0f, 0.45f, t);
            SetLight(Color.Lerp(dayColor, duskColor, Smooth(u)),
                     Mathf.Lerp(dayIntensity, duskIntensity, Smooth(u)));
        }
        else if (t < 0.65f)
        {
            float u = Mathf.InverseLerp(0.45f, 0.65f, t);
            SetLight(Color.Lerp(duskColor, nightColor, Smooth(u)),
                     Mathf.Lerp(duskIntensity, nightIntensity, Smooth(u)));
        }
        else
        {
            float u = Mathf.InverseLerp(0.65f, 1f, t);
            SetLight(Color.Lerp(nightColor, dayColor, Smooth(u)),
                     Mathf.Lerp(nightIntensity, dayIntensity, Smooth(u)));
        }
    }

    private static float Smooth(float x) => x * x * (3f - 2f * x);

    private void SetLight(Color c, float i)
    {
        globalLight.color = c;
        globalLight.intensity = i;
    }

    // Handy debug buttons (call from inspector via context menu or UI)
    public void SetDay()  { autoRun = false; time01 = 0.10f; ApplyLighting(time01); }
    public void SetDusk() { autoRun = false; time01 = 0.50f; ApplyLighting(time01); }
    public void SetNight(){ autoRun = false; time01 = 0.80f; ApplyLighting(time01); }
}
